    SELECT SEQ_INV_TX.NEXTVAL FROM DUAL

INSERT INTO INVENTORY_TRANSACTIONS (
      INVENTORY_TRANSACTION_ID
    , TRANSACTION_TYPE
    , REASON
    , TRANSACTION_MEMO
    , CREATED_BY
    , STORE_ID
    , RECEIPT_ID
    , STORE_CLOSING_ID
) VALUES (
      #{inventoryTransactionId}
    , #{transactionType}
    , #{reason}
    , #{transactionMemo}
    , #{createdBy}
    , #{storeId}
    , #{receiptId}
    , #{storeClosingId}
)


    SELECT SEQ_INV_TX_ITEM.NEXTVAL FROM DUAL

INSERT INTO INVENTORY_TRANSACTION_ITEMS (
       INVENTORY_TRANSACTION_ITEM_ID
     , BEFORE_QUANTITY
     , AFTER_QUANTITY
     , INVENTORY_TRANSACTION_ID
     , STORE_INVENTORY_ID
  ) VALUES (
       #{item.inventoryTransactionItemId}
     , #{item.beforeQuantity}
     , #{item.afterQuantity}
     , #{item.inventoryTransactionId}
     , #{item.storeInventoryId}
  )
